package org.eclipse.rdf4j.sail.lmdb.config;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LmdbUnifiedStrategyConfigTest {

	@Test
	void defaultsToUnifiedEstimator() {
		assertEquals("unified", new LmdbStoreConfig().getSketchEstimatorStrategy());
	}

	@Test
	void legacyStrategiesNormalizeToUnifiedEstimator() {
		for (String legacy : new String[] { "omni", "fastagms", "countmin", "countmin-dual", "tuple",
				"joinsketch" }) {
			assertEquals("unified", new LmdbStoreConfig().setSketchEstimatorStrategy(legacy)
					.getSketchEstimatorStrategy());
		}
	}
}
